#!/bin/bash# 打印信息颜色配置GREEN='\033[0;32m'RED='\033[0;31m'NC='\033[0m' # No Colorecho -e "${GREEN}=== 开始安装 Pi Water 控制系统服务 ===${NC}"# 1. 检查文件是否存在SERVICE_FILE="piwater.service"if [ ! -f "$SERVICE_FILE" ]; then    echo -e "${RED}错误: 找不到服务配置文件 piwater.service${NC}"    echo "请确保在执行此脚本时，当前目录下存在该文件。"    exit 1fi# 2. 复制服务文件到 systemd 目录echo "复制服务文件到 /etc/systemd/system/ ..."sudo cp $SERVICE_FILE /etc/systemd/system/sudo chmod 644 /etc/systemd/system/$SERVICE_FILE# 3. 重新加载 systemd 守护进程以应用更改echo "重新加载 systemd 守护进程..."sudo systemctl daemon-reload# 4. 启用服务开机自启echo "启用开机自启功能..."sudo systemctl enable piwater.service# 5. 立刻启动服务echo "尝试立即启动服务..."sudo systemctl start piwater.service# 6. 检查服务运行状态echo -e "${GREEN}=== 安装完成！ ===${NC}"echo "以下是当前的运行状态 (可能会要求输入 root 密码):"sudo systemctl status piwater.service --no-pagerecho -e "\n${GREEN}提示：${NC}"echo "查看实时日志命令: journalctl -u piwater.service -f"echo "停止服务命令: sudo systemctl stop piwater.service"echo "重启服务命令: sudo systemctl restart piwater.service"